{"content": "     1|"use client"
     2|import { useState, useEffect } from "react"
     3|
     4|type Lang = "es" | "en" | "gn"
     5|
     6|const labels: Record<Lang, string> = { es: "ES", en: "EN", gn: "GN" }
     7|const flags: Record<Lang, string> = { es: "🇵🇾", en: "🇺🇸", gn: "🇵🇾" }
     8|const langs: Lang[] = ["es", "en", "gn"]
     9|
    10|export function LanguageSwitcher() {
    11|  const [lang, setLangState] = useState<Lang>("es")
    12|
    13|  useEffect(() => {
    14|    try {
    15|      const saved = localStorage.getItem("viajero_lang") as Lang | null
    16|      if (saved && langs.includes(saved)) setLangState(saved)
    17|    } catch {}
    18|  }, [])
    19|
    20|  const switchLang = (l: Lang) => {
    21|    setLangState(l)
    22|    localStorage.setItem("viajero_lang", l)
    23|    // Reload content by re-rendering (simple approach: reload)
    24|    const url = new URL(window.location.href)
    25|    url.searchParams.set("lang", l)
    26|    window.location.href = url.toString()
    27|  }
    28|
    29|  return (
    30|    <div className="flex items-center gap-1">
    31|      {langs.map((l) => (
    32|        <button key={l} onClick={() => switchLang(l)}
    33|          className={`flex h-6 w-7 items-center justify-center rounded text-[10px] font-bold transition-all ${
    34|            lang === l ? "bg-primary text-primary-foreground" : "text-muted-foreground hover:text-foreground"
    35|          }`}>
    36|          {labels[l]}
    37|        </button>
    38|      ))}
    39|    </div>
    40|  )
    41|}
